// v63 markers: Mission Contract · Evidence Docket · Chronicle
(()=>{
  const stages=[
    ['Objective','capture the user intent'],['Contract','define success, constraints, boundaries'],['Workstreams','split into proof-bearing work'],['Claims','make claims explicit'],['Evidence','assemble docket requirements'],['Verification','select verifier mesh'],['Decision','compose governed state'],['Action','scope next actions'],['Chronicle','record reusable capability'],['DONE','human review ready']
  ];
  const routes=[
    {id:'evidence',href:'evidence-docket-composer.html',title:'Evidence Docket Composer',group:'Evidence',why:'Build the proof room before the claim.'},
    {id:'until',href:'until-done-mission-control.html',title:'Until-DONE Mission Control',group:'Mission OS',why:'Run objective → proof → governed decision state.'},
    {id:'rsi',href:'loop-to-rsi-control-room.html',title:'Loop → RSI Control Room',group:'Loop & RSI',why:'Turn restartable loops into evidence-gated RSI governance.'},
    {id:'settlement',href:'proof-settlement-lifecycle.html',title:'Proof-Settlement Lifecycle',group:'Settlement',why:'Review Request → Escrow → Execute → Proof → Validate → Settle → Chronicle.'},
    {id:'route',href:'experience-command.html',title:'Experience Command',group:'Start here',why:'Search every route and choose the right public-safe proof path.'},
    {id:'legal',href:'legal.html',title:'Legal / Data-Zero Boundary',group:'Boundary',why:'Confirm no data wanted, no advice, no wallet, no production authority.'},
    {id:'ask',href:'ask-goalos.html',title:'Ask GoalOS',group:'Question router',why:'Ask a question and receive a local route receipt.'},
    {id:'institution',href:'canonical-proof-institution.html',title:'Canonical Proof Institution',group:'Institution',why:'Inspect the public proof institution and route manifest.'}
  ];
  const presets={
    'stakeholder-review':'Evaluate whether a public-safe AI work settlement page is ready for stakeholder review, including proof, risk, replay, and next actions.',
    'proof-docket':'Create a public-safe Evidence Docket for a claim about GoalOS proof-settled machine work, including what is claimed, not claimed, evidence, replay, risk, and human review.',
    'loop-rsi':'Turn a long-running agent loop into a proof-gated RSI governance package with restart state, ECI, baselines, Move-37 handling, dossier, Chronicle, and human boundary.',
    'settlement-readiness':'Assess whether a machine-work item is settlement-ready: request, execution, proof bundle, validator review, replay, dispute window, Chronicle, and boundary.',
    'route-me':'Help me find the best GoalOS page or demo for my objective, then explain the route and next action in simple language.'
  };
  const terms={proof:['proof','evidence','docket','claim','verify','audit','source','replay'],rsi:['rsi','recursive','invention','move','baseline','eci','loop','restart','dossier'],settlement:['settle','settlement','escrow','job','proofbundle','fund','payment','validate'],legal:['legal','privacy','gdpr','regulation','investment','tax','risk','wallet','data','cookie'],route:['where','find','page','route','start','begin','all pages','guide']};
  const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
  const esc=s=>String(s||'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  const norm=s=>String(s||'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim();
  let last=null, timer=null;
  function scoreObjective(text){const n=norm(text); const scores={proof:0,rsi:0,settlement:0,legal:0,route:0}; for(const [k,arr] of Object.entries(terms)){for(const t of arr){if(n.includes(t)) scores[k]+=1;}} return scores;}
  function pickRoutes(text,risk){const s=scoreObjective(text); let ids=[]; if(s.legal||risk!=='public-safe') ids.push('legal'); if(s.rsi) ids.push('rsi','evidence','until'); if(s.settlement) ids.push('settlement','evidence','legal'); if(s.proof) ids.push('evidence','until','institution'); if(s.route||!ids.length) ids.push('route','ask','institution'); ids.push('evidence','until','legal','route'); return ids.map(id=>routes.find(r=>r.id===id)).filter(Boolean).filter((r,i,a)=>a.findIndex(x=>x.id===r.id)===i).slice(0,5);}
  function buildMission(){const objective=$('[data-objective]').value.trim(); if(!objective){$('[data-objective]').classList.add('mission-shake'); setTimeout(()=>$('[data-objective]').classList.remove('mission-shake'),360); return null;} const preset=$('[data-preset]').value, posture=$('[data-posture]').value, risk=$('[data-risk]').value; const selected=pickRoutes(objective,risk); const scores=scoreObjective(objective); const readiness=Math.min(96,58+Object.values(scores).reduce((a,b)=>a+b,0)*5+(risk==='public-safe'?10:0)); const title = objective.length>86 ? objective.slice(0,83)+'…' : objective; const contract={objective,missionPreset:preset,posture,riskClass:risk,successCriteria:['mission contract is explicit','claims are separated from assumptions','evidence requirements are visible','risk and boundary are readable','reviewer receives a next action'],failureCriteria:['missing evidence','unresolved contradiction','private or regulated data entered','unsupported factual certification','wallet/funds/production authority requested'],allowedOperations:['browser-local planning','public-safe route handoff','docket outline generation','local receipt export'],blockedOperations:['external network request','wallet connection','token approval','transaction broadcast','legal/financial/investment advice','production authority']}; const docket=['Manifest','Claims Matrix','Source Provenance','Proof Packets','Verifier Report','Risk Ledger','Replay Path','Decision State','Action Graph','Chronicle Entry'].map((name,i)=>({name,summary:['objective, version, signer, boundary','what is claimed, not claimed, required evidence','source reality, freshness, citation plan','trace roots, outputs, cost, signatures','validator judgment, assumptions, contradiction coverage','residual risk, blocked actions, privacy boundary','how a reviewer can reproduce or inspect','publish, revise, quarantine, or stop','owners, dependencies, rollback','accepted facts and reusable capability'][i],score:Math.max(42,Math.min(98,readiness-i*3))})); const decision=readiness>=82?'HUMAN_REVIEW_READY':'DRAFT_REQUIRES_EVIDENCE'; const actionGraph=selected.map((r,i)=>({step:i+1,title:r.title,href:r.href,why:r.why})); return {receiptType:'GoalOSMissionAutopilotReceipt',version:'v63-mission-autopilot',generatedAt:new Date().toISOString(),contract,docket,decisionState:{verdict:decision,doneReadiness:readiness,proofDebt:100-readiness,humanReviewRequired:true,productionAuthority:false,walletActions:false,networkRequests:false,userDataRetained:false},actionGraph,chronicleEntry:{status:'local-demo-only',reusableCapability:'MissionAutopilotRoutePackage',nextBestRoute:selected[0]},boundary:{publicSafe:true,noAccount:true,noFormSubmission:true,noWallet:true,noTokenApproval:true,noNetworkRequest:true,noAnalytics:true,noCookies:true,noBrowserStorage:true,noUserDataRetained:true,noTransactionBroadcast:true,noProductionAuthority:true}};}
  function renderStages(activeIndex=0,done=-1){const grid=$('[data-stage-grid]'); grid.innerHTML=stages.map((s,i)=>`<div class="mission-stage ${i===activeIndex?'active':''} ${i<=done?'done':''}"><small>${String(i+1).padStart(2,'0')}</small><b>${esc(s[0])}</b><span>${esc(s[1])}</span></div>`).join('');}
  function renderMission(m){if(!m)return; last=m; $('[data-contract-title]').textContent=m.contract.objective.slice(0,96); $('[data-contract]').innerHTML=`<ul><li><b>Preset:</b> ${esc(m.contract.missionPreset)}</li><li><b>Posture:</b> ${esc(m.contract.posture)}</li><li><b>Risk class:</b> ${esc(m.contract.riskClass)}</li><li><b>Success:</b> ${esc(m.contract.successCriteria.slice(0,3).join('; '))}</li></ul><div class="mission-chip-row">${m.contract.blockedOperations.slice(0,6).map(x=>`<span class="mission-chip">No ${esc(x)}</span>`).join('')}</div>`; $('[data-docket]').innerHTML=m.docket.map(d=>`<div class="docket-card"><b>${esc(d.name)}</b><span>${esc(d.summary)}</span><i style="width:${d.score}%"></i></div>`).join(''); $('[data-verdict]').textContent=m.decisionState.verdict.replace(/_/g,' '); $('[data-decision]').innerHTML=`<ul><li>DONE readiness: ${m.decisionState.doneReadiness}%</li><li>Proof debt: ${m.decisionState.proofDebt}%</li><li>Human review required: yes</li><li>Production authority: no</li></ul><pre class="receipt-preview">${esc(JSON.stringify({verdict:m.decisionState.verdict,next:m.chronicleEntry.nextBestRoute.title,route:m.chronicleEntry.nextBestRoute.href},null,2))}</pre>`; $('[data-route-cards]').innerHTML=m.actionGraph.map(a=>`<a href="${esc(a.href)}"><small>Step ${a.step}</small><b>${esc(a.title)}</b><span>${esc(a.why)}</span></a>`).join(''); $('[data-route-label]').textContent=m.chronicleEntry.nextBestRoute.title; $('[data-readiness]').textContent=m.decisionState.doneReadiness+'%'; $('[data-progress]').style.width=m.decisionState.doneReadiness+'%';}
  function run(){const mission=buildMission(); if(!mission)return; clearInterval(timer); let i=0; renderMission(mission); timer=setInterval(()=>{renderStages(i,i-1); $('[data-active-stage]').textContent=stages[i][0]; i++; if(i>=stages.length){clearInterval(timer); renderStages(stages.length-1,stages.length-1); $('[data-active-stage]').textContent='DONE · human review package ready';}},280);}
  function download(){const m=last||buildMission(); if(!m)return; const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([JSON.stringify(m,null,2)],{type:'application/json'})); a.download='goalos-mission-autopilot-receipt-v63.json'; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),900);}
  function copyBrief(){const m=last||buildMission(); if(!m)return; const text=['GoalOS Mission Autopilot v63',m.contract.objective,'Verdict: '+m.decisionState.verdict,'DONE readiness: '+m.decisionState.doneReadiness+'%','Next route: '+m.chronicleEntry.nextBestRoute.title+' — '+m.chronicleEntry.nextBestRoute.href,'Boundary: local planning only; no wallet, no network request, no user data retained, no production authority.'].join('\n'); if(navigator.clipboard&&navigator.clipboard.writeText) navigator.clipboard.writeText(text).catch(()=>{});}
  function init(){renderStages(); $('[data-preset]').addEventListener('change',e=>{$('[data-objective]').value=presets[e.target.value]||$('[data-objective]').value;}); $('[data-run-autopilot]').addEventListener('click',run); $('[data-download-receipt]').addEventListener('click',download); $('[data-copy-brief]').addEventListener('click',copyBrief); renderMission(buildMission());}
  window.GOALOS_MISSION_AUTOPILOT_V63={buildMission,pickRoutes,stages};
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init); else init();
})();
